import { useState, useEffect } from 'react';
import React from 'react';
import { Plus, Users, Shield, ScrollText } from 'lucide-react';
import { Modal } from '../../components/ui/Modal';
import { StatusBadge, RoleBadge } from '../../components/ui/Badge';
import { AuditLogTable } from '../../components/admin/AuditLogTable';
import { RoleManagementPage } from './RoleManagementPage';
import { useRoles } from '../../hooks/useRoles';
import { useUsers, useUpdateUserRole, useDeactivateUser, useActivateUser } from '../../hooks/useUsers';
import { useAuthStore } from '../../store/authStore';
import { hasPermission } from '../../lib/permissionUtils';
import { PermissionGuard } from '../../components/auth/Guards';
import { PERMISSIONS } from '../../lib/constants';
import type { Role } from '../../lib/types';

import { clsx } from 'clsx';
import { Button } from '../../components/ui/Button';



// ΓöÇΓöÇΓöÇ Assign Role Modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function AssignRoleModal({
    userId,
    currentRoleId,
    onClose,
}: {
    userId: string;
    currentRoleId: string;
    onClose: () => void;
}) {
    const { data: roles = [] } = useRoles();
    const updateRole = useUpdateUserRole();
    const [roleId, setRoleId] = useState(currentRoleId);

    const handleSave = async () => {
        await updateRole.mutateAsync({ userId, roleId });
        onClose();
    };

    return (
        <div className="space-y-4">
            <div>
                <label className="block text-xs font-medium text-gray-600 mb-1">Select Role</label>
                <select
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                    title="Select role"
                    aria-label="Select role"
                    value={roleId}
                    onChange={(e) => setRoleId(e.target.value)}
                >
                    {roles.map((r: Role) => (
                        <option key={r.id} value={r.id}>{r.name}</option>
                    ))}
                </select>
            </div>
            <div className="flex justify-end gap-3">
                <Button variant="secondary" onClick={onClose}>Cancel</Button>
                <Button variant="primary" loading={updateRole.isPending} onClick={handleSave}>Assign Role</Button>
            </div>
        </div>
    );
}

// ΓöÇΓöÇΓöÇ Users Table ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function UsersTable() {
    const { data: users = [], isLoading: usersLoading } = useUsers();
    const deactivateUser = useDeactivateUser();
    const activateUser = useActivateUser();
    const [assignRoleUser, setAssignRoleUser] = useState<{ id: string; role_id: string } | null>(null);

    return (
        <PermissionGuard permission={PERMISSIONS.ADMIN_USERS_VIEW}>
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead>
                            <tr className="border-b border-gray-100">
                                {['Name', 'Email', 'Role', 'Status', 'Joined', ''].map((h) => (
                                    <th key={h} className="text-left text-xs font-semibold text-gray-500 uppercase tracking-wide px-5 py-3.5">
                                        {h}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {usersLoading ? (
                                <tr>
                                    <td colSpan={6} className="px-5 py-12 text-center text-gray-400 text-sm">Loading users...</td>
                                </tr>
                            ) : users.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="px-5 py-12 text-center">
                                        <Users size={36} className="text-gray-200 mx-auto mb-2" />
                                        <p className="text-gray-400 text-sm">No users found</p>
                                    </td>
                                </tr>
                            ) : (
                                users.map((user) => (
                                    <tr key={user.id} className="hover:bg-gray-50/60 transition-colors">
                                        <td className="px-5 py-3.5">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center shrink-0">
                                                    <span className="text-blue-600 text-xs font-bold">
                                                        {(user.full_name ?? user.email).charAt(0).toUpperCase()}
                                                    </span>
                                                </div>
                                                <span className="text-sm font-medium text-gray-900">{user.full_name ?? 'ΓÇö'}</span>
                                            </div>
                                        </td>
                                        <td className="px-5 py-3.5 text-sm text-gray-500">{user.email}</td>
                                        <td className="px-5 py-3.5">
                                            {user.role && <RoleBadge roleName={user.role.name} />}
                                        </td>
                                        <td className="px-5 py-3.5">
                                            <StatusBadge status={user.is_active ? 'active' : 'inactive'} />
                                        </td>
                                        <td className="px-5 py-3.5 text-xs text-gray-400">
                                            {new Date(user.created_at).toLocaleDateString()}
                                        </td>
                                        <td className="px-5 py-3.5">
                                            <div className="flex items-center gap-2">
                                                <PermissionGuard permission={PERMISSIONS.ADMIN_ROLES_ASSIGN}>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => setAssignRoleUser({ id: user.id, role_id: user.role_id })}
                                                    >
                                                        Assign Role
                                                    </Button>
                                                </PermissionGuard>
                                                <PermissionGuard permission={PERMISSIONS.ADMIN_USERS_DEACTIVATE}>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => {
                                                            if (user.is_active) {
                                                                deactivateUser.mutate(user.id);
                                                            } else {
                                                                activateUser.mutate(user.id);
                                                            }
                                                        }}
                                                        className={user.is_active ? 'text-red-400 hover:text-red-600 hover:bg-red-50' : 'text-green-500 hover:bg-green-50'}
                                                    >
                                                        {user.is_active ? 'Deactivate' : 'Activate'}
                                                    </Button>
                                                </PermissionGuard>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {assignRoleUser && (
                <Modal title="Assign Role" onClose={() => setAssignRoleUser(null)} size="sm">
                    <AssignRoleModal
                        userId={assignRoleUser.id}
                        currentRoleId={assignRoleUser.role_id}
                        onClose={() => setAssignRoleUser(null)}
                    />
                </Modal>
            )}
        </PermissionGuard>
    );
}

// ΓöÇΓöÇΓöÇ Main Admin Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function AdminPage() {
    useAuthStore((state) => state.permissions);
    const [activeTab, setActiveTab] = useState<'roles' | 'users' | 'audit'>('roles');

    const canManageRoles = hasPermission(PERMISSIONS.ADMIN_ROLES_MANAGE);
    const canViewUsers = hasPermission(PERMISSIONS.ADMIN_USERS_VIEW);
    const canViewAudit = hasPermission(PERMISSIONS.ADMIN_AUDIT_VIEW);

    useEffect(() => {
        if (!canManageRoles && !canViewUsers && !canViewAudit) return;

        if (activeTab === 'roles' && !canManageRoles) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            if (canViewUsers) setActiveTab('users');
            // eslint-disable-next-line react-hooks/set-state-in-effect
            else if (canViewAudit) setActiveTab('audit');
        }
    }, [canManageRoles, canViewUsers, canViewAudit, activeTab]);

    const tabs: { key: 'roles' | 'users' | 'audit'; label: string; icon: React.ReactNode }[] = [
        canManageRoles ? { key: 'roles', label: 'Roles', icon: <Shield size={15} /> } : null,
        canViewUsers ? { key: 'users', label: 'Users', icon: <Users size={15} /> } : null,
        canViewAudit ? { key: 'audit', label: 'Audit Log', icon: <ScrollText size={15} /> } : null,
    ].filter(Boolean) as { key: 'roles' | 'users' | 'audit'; label: string; icon: React.ReactNode }[];

    return (
        <div className="max-w-7xl mx-auto space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Admin Panel</h1>
                    <p className="text-gray-500 text-sm mt-0.5">Manage roles, permissions, and users</p>
                </div>
                {activeTab === 'roles' && canManageRoles && (
                    <Button variant="primary" icon={<Plus size={16} />} >
                        New Role
                    </Button>
                )}
            </div>

            <div className="flex gap-1 bg-gray-100 p-1 rounded-xl w-fit">
                {tabs.map(({ key, label, icon }) => (
                    <button
                        key={key}
                        onClick={() => setActiveTab(key)}
                        className={clsx(
                            'flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all',
                            activeTab === key
                                ? 'bg-white text-gray-900 shadow-sm'
                                : 'text-gray-500 hover:text-gray-700'
                        )}
                    >
                        {icon}
                        {label}
                    </button>
                ))}
            </div>

            <div className="mt-6">
                {activeTab === 'roles' && canManageRoles && <RoleManagementPage />}
                {activeTab === 'users' && canViewUsers && <UsersTable />}
                {activeTab === 'audit' && canViewAudit && <AuditLogTable />}
            </div>
        </div>
    );
}

